SELECT count(*) FROM cast_info, title, name, aka_name, movie_companies, company_type, role_type, char_name, company_name WHERE cast_info.movie_id = title.id AND cast_info.person_id = name.id AND aka_name.person_id = name.id AND movie_companies.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND cast_info.role_id = role_type.id AND cast_info.person_role_id = char_name.id AND movie_companies.company_id = company_name.id;